1200 static void simplifyRecipe(VPSingleDefRecipe *Def, VPTypeAnalysis &TypeInfo) {
1201   VPlan *Plan = Def->getParent()->getPlan();
1202 
1203   // Simplification of live-in IR values for SingleDef recipes using
1204   // InstSimplifyFolder.
1205   const DataLayout &DL =
1206       Plan->getScalarHeader()->getIRBasicBlock()->getDataLayout();
1207   if (VPValue *V = tryToFoldLiveIns(*Def, Def->operands(), DL, TypeInfo))
1208     return Def->replaceAllUsesWith(V);
1209 
1210   // Fold PredPHI LiveIn -> LiveIn.
1211   if (auto *PredPHI = dyn_cast<VPPredInstPHIRecipe>(Def)) {
1212     VPValue *Op = PredPHI->getOperand(0);
1213     if (isa<VPIRValue>(Op))
1214       PredPHI->replaceAllUsesWith(Op);
1215   }
1216 
1217   VPBuilder Builder(Def);
1218   VPValue *A;
1219   if (match(Def, m_Trunc(m_ZExtOrSExt(m_VPValue(A))))) {
1220     Type *TruncTy = TypeInfo.inferScalarType(Def);
1221     Type *ATy = TypeInfo.inferScalarType(A);
1222     if (TruncTy == ATy) {
1223       Def->replaceAllUsesWith(A);
1224     } else {
1225       // Don't replace a scalarizing recipe with a widened cast.
1226       if (isa<VPReplicateRecipe>(Def))
1227         return;
1228       if (ATy->getScalarSizeInBits() < TruncTy->getScalarSizeInBits()) {
1229 
1230         unsigned ExtOpcode = match(Def->getOperand(0), m_SExt(m_VPValue()))
1231                                  ? Instruction::SExt
1232                                  : Instruction::ZExt;
1233         auto *Ext = Builder.createWidenCast(Instruction::CastOps(ExtOpcode), A,
1234                                             TruncTy);
1235         if (auto *UnderlyingExt = Def->getOperand(0)->getUnderlyingValue()) {
1236           // UnderlyingExt has distinct return type, used to retain legacy cost.
1237           Ext->setUnderlyingValue(UnderlyingExt);
1238         }
1239         Def->replaceAllUsesWith(Ext);
1240       } else if (ATy->getScalarSizeInBits() > TruncTy->getScalarSizeInBits()) {
1241         auto *Trunc = Builder.createWidenCast(Instruction::Trunc, A, TruncTy);
1242         Def->replaceAllUsesWith(Trunc);
1243       }
1244     }
1245 #ifndef NDEBUG
1246     // Verify that the cached type info is for both A and its users is still
1247     // accurate by comparing it to freshly computed types.
1248     VPTypeAnalysis TypeInfo2(*Plan);
1249     assert(TypeInfo.inferScalarType(A) == TypeInfo2.inferScalarType(A));
1250     for (VPUser *U : A->users()) {
1251       auto *R = cast<VPRecipeBase>(U);
1252       for (VPValue *VPV : R->definedValues())
1253         assert(TypeInfo.inferScalarType(VPV) == TypeInfo2.inferScalarType(VPV));
1254     }
1255 #endif
1256   }
1257 
1258   // Simplify (X && Y) || (X && !Y) -> X.
1259   // TODO: Split up into simpler, modular combines: (X && Y) || (X && Z) into X
1260   // && (Y || Z) and (X || !X) into true. This requires queuing newly created
1261   // recipes to be visited during simplification.
1262   VPValue *X, *Y, *Z;
1263   if (match(Def,
1264             m_c_BinaryOr(m_LogicalAnd(m_VPValue(X), m_VPValue(Y)),
1265                          m_LogicalAnd(m_Deferred(X), m_Not(m_Deferred(Y)))))) {
1266     Def->replaceAllUsesWith(X);
1267     Def->eraseFromParent();
1268     return;
1269   }
1270 
1271   // x | 1 -> 1
1272   if (match(Def, m_c_BinaryOr(m_VPValue(X), m_AllOnes())))
1273     return Def->replaceAllUsesWith(Def->getOperand(Def->getOperand(0) == X));
1274 
1275   // x | 0 -> x
1276   if (match(Def, m_c_BinaryOr(m_VPValue(X), m_ZeroInt())))
1277     return Def->replaceAllUsesWith(X);
1278 
1279   // x | !x -> AllOnes
1280   if (match(Def, m_c_BinaryOr(m_VPValue(X), m_Not(m_Deferred(X))))) {
1281     return Def->replaceAllUsesWith(Plan->getOrAddLiveIn(
1282         ConstantInt::getAllOnesValue(TypeInfo.inferScalarType(Def))));
1283   }
1284 
1285   // x & 0 -> 0
1286   if (match(Def, m_c_BinaryAnd(m_VPValue(X), m_ZeroInt())))
1287     return Def->replaceAllUsesWith(Def->getOperand(Def->getOperand(0) == X));
1288 
1289   // x & AllOnes -> x
1290   if (match(Def, m_c_BinaryAnd(m_VPValue(X), m_AllOnes())))
1291     return Def->replaceAllUsesWith(X);
1292 
1293   // x && false -> false
1294   if (match(Def, m_LogicalAnd(m_VPValue(X), m_False())))
1295     return Def->replaceAllUsesWith(Def->getOperand(1));
1296 
1297   // (x && y) || (x && z) -> x && (y || z)
1298   if (match(Def, m_c_BinaryOr(m_LogicalAnd(m_VPValue(X), m_VPValue(Y)),
1299                               m_LogicalAnd(m_Deferred(X), m_VPValue(Z)))) &&
1300       // Simplify only if one of the operands has one use to avoid creating an
1301       // extra recipe.
1302       (!Def->getOperand(0)->hasMoreThanOneUniqueUser() ||
1303        !Def->getOperand(1)->hasMoreThanOneUniqueUser()))
1304     return Def->replaceAllUsesWith(
1305         Builder.createLogicalAnd(X, Builder.createOr(Y, Z)));
1306 
1307   // x && !x -> 0
1308   if (match(Def, m_LogicalAnd(m_VPValue(X), m_Not(m_Deferred(X)))))
1309     return Def->replaceAllUsesWith(Plan->getFalse());
1310 
1311   if (match(Def, m_Select(m_VPValue(), m_VPValue(X), m_Deferred(X))))
1312     return Def->replaceAllUsesWith(X);
1313 
1314   // select c, false, true -> not c
1315   VPValue *C;
1316   if (match(Def, m_Select(m_VPValue(C), m_False(), m_True())))
1317     return Def->replaceAllUsesWith(Builder.createNot(C));
1318 
1319   // select !c, x, y -> select c, y, x
1320   if (match(Def, m_Select(m_Not(m_VPValue(C)), m_VPValue(X), m_VPValue(Y)))) {
1321     Def->setOperand(0, C);
1322     Def->setOperand(1, Y);
1323     Def->setOperand(2, X);
1324     return;
1325   }
1326 
1327   // Reassociate (x && y) && z -> x && (y && z) if x has multiple users. With
1328   // tail folding it is likely that x is a header mask and can be simplified
1329   // further.
1330   if (match(Def, m_LogicalAnd(m_LogicalAnd(m_VPValue(X), m_VPValue(Y)),
1331                               m_VPValue(Z))) &&
1332       X->hasMoreThanOneUniqueUser())
1333     return Def->replaceAllUsesWith(
1334         Builder.createLogicalAnd(X, Builder.createLogicalAnd(Y, Z)));
1335 
1336   if (match(Def, m_c_Add(m_VPValue(A), m_ZeroInt())))
1337     return Def->replaceAllUsesWith(A);
1338 
1339   if (match(Def, m_c_Mul(m_VPValue(A), m_One())))
1340     return Def->replaceAllUsesWith(A);
1341 
1342   if (match(Def, m_c_Mul(m_VPValue(A), m_ZeroInt())))
1343     return Def->replaceAllUsesWith(
1344         Def->getOperand(0) == A ? Def->getOperand(1) : Def->getOperand(0));
1345 
1346   const APInt *APC;
1347   if (match(Def, m_c_Mul(m_VPValue(A), m_APInt(APC))) && APC->isPowerOf2())
1348     return Def->replaceAllUsesWith(Builder.createNaryOp(
1349         Instruction::Shl,
1350         {A, Plan->getConstantInt(APC->getBitWidth(), APC->exactLogBase2())},
1351         *cast<VPRecipeWithIRFlags>(Def), Def->getDebugLoc()));
1352 
1353   // Don't convert udiv to lshr inside a replicate region, as VPInstructions are
1354   // not allowed in them.
1355   const VPRegionBlock *ParentRegion = Def->getParent()->getParent();
1356   bool IsInReplicateRegion = ParentRegion && ParentRegion->isReplicator();
1357   if (!IsInReplicateRegion && match(Def, m_UDiv(m_VPValue(A), m_APInt(APC))) &&
1358       APC->isPowerOf2())
1359     return Def->replaceAllUsesWith(Builder.createNaryOp(
1360         Instruction::LShr,
1361         {A, Plan->getConstantInt(APC->getBitWidth(), APC->exactLogBase2())},
1362         *cast<VPRecipeWithIRFlags>(Def), Def->getDebugLoc()));
1363 
1364   if (match(Def, m_Not(m_VPValue(A)))) {
1365     if (match(A, m_Not(m_VPValue(A))))
1366       return Def->replaceAllUsesWith(A);
1367 
1368     // Try to fold Not into compares by adjusting the predicate in-place.
1369     CmpPredicate Pred;
1370     if (match(A, m_Cmp(Pred, m_VPValue(), m_VPValue()))) {
1371       auto *Cmp = cast<VPRecipeWithIRFlags>(A);
1372       if (all_of(Cmp->users(),
1373                  match_fn(m_CombineOr(
1374                      m_Not(m_Specific(Cmp)),
1375                      m_Select(m_Specific(Cmp), m_VPValue(), m_VPValue()))))) {
1376         Cmp->setPredicate(CmpInst::getInversePredicate(Pred));
1377         for (VPUser *U : to_vector(Cmp->users())) {
1378           auto *R = cast<VPSingleDefRecipe>(U);
1379           if (match(R, m_Select(m_Specific(Cmp), m_VPValue(X), m_VPValue(Y)))) {
1380             // select (cmp pred), x, y -> select (cmp inv_pred), y, x
1381             R->setOperand(1, Y);
1382             R->setOperand(2, X);
1383           } else {
1384             // not (cmp pred) -> cmp inv_pred
1385             assert(match(R, m_Not(m_Specific(Cmp))) && "Unexpected user");
1386             R->replaceAllUsesWith(Cmp);
1387           }
1388         }
1389         // If Cmp doesn't have a debug location, use the one from the negation,
1390         // to preserve the location.
1391         if (!Cmp->getDebugLoc() && Def->getDebugLoc())
1392           Cmp->setDebugLoc(Def->getDebugLoc());
1393       }
1394     }
1395   }
1396 
1397   // Fold any-of (fcmp uno %A, %A), (fcmp uno %B, %B), ... ->
1398   //      any-of (fcmp uno %A, %B), ...
1399   if (match(Def, m_AnyOf())) {
1400     SmallVector<VPValue *, 4> NewOps;
1401     VPRecipeBase *UnpairedCmp = nullptr;
1402     for (VPValue *Op : Def->operands()) {
1403       VPValue *X;
1404       if (Op->getNumUsers() > 1 ||
1405           !match(Op, m_SpecificCmp(CmpInst::FCMP_UNO, m_VPValue(X),
1406                                    m_Deferred(X)))) {
1407         NewOps.push_back(Op);
1408       } else if (!UnpairedCmp) {
1409         UnpairedCmp = Op->getDefiningRecipe();
1410       } else {
1411         NewOps.push_back(Builder.createFCmp(CmpInst::FCMP_UNO,
1412                                             UnpairedCmp->getOperand(0), X));
1413         UnpairedCmp = nullptr;
1414       }
1415     }
1416 
1417     if (UnpairedCmp)
1418       NewOps.push_back(UnpairedCmp->getVPSingleValue());
1419 
1420     if (NewOps.size() < Def->getNumOperands()) {
1421       VPValue *NewAnyOf = Builder.createNaryOp(VPInstruction::AnyOf, NewOps);
1422       return Def->replaceAllUsesWith(NewAnyOf);
1423     }
1424   }
1425 
1426   // Fold (fcmp uno %X, %X) or (fcmp uno %Y, %Y) -> fcmp uno %X, %Y
1427   // This is useful for fmax/fmin without fast-math flags, where we need to
1428   // check if any operand is NaN.
1429   if (match(Def, m_BinaryOr(m_SpecificCmp(CmpInst::FCMP_UNO, m_VPValue(X),
1430                                           m_Deferred(X)),
1431                             m_SpecificCmp(CmpInst::FCMP_UNO, m_VPValue(Y),
1432                                           m_Deferred(Y))))) {
1433     VPValue *NewCmp = Builder.createFCmp(CmpInst::FCMP_UNO, X, Y);
1434     return Def->replaceAllUsesWith(NewCmp);
1435   }
1436 
1437   // Remove redundant DerviedIVs, that is 0 + A * 1 -> A and 0 + 0 * x -> 0.
1438   if ((match(Def, m_DerivedIV(m_ZeroInt(), m_VPValue(A), m_One())) ||
1439        match(Def, m_DerivedIV(m_ZeroInt(), m_ZeroInt(), m_VPValue()))) &&
1440       TypeInfo.inferScalarType(Def->getOperand(1)) ==
1441           TypeInfo.inferScalarType(Def))
1442     return Def->replaceAllUsesWith(Def->getOperand(1));
1443 
1444   if (match(Def, m_VPInstruction<VPInstruction::WideIVStep>(m_VPValue(X),
1445                                                             m_One()))) {
1446     Type *WideStepTy = TypeInfo.inferScalarType(Def);
1447     if (TypeInfo.inferScalarType(X) != WideStepTy)
1448       X = Builder.createWidenCast(Instruction::Trunc, X, WideStepTy);
1449     Def->replaceAllUsesWith(X);
