1340     return Def->replaceAllUsesWith(A);
1341 
1342   if (match(Def, m_c_Mul(m_VPValue(A), m_ZeroInt())))
1343     return Def->replaceAllUsesWith(
1344         Def->getOperand(0) == A ? Def->getOperand(1) : Def->getOperand(0));
