2259   case Instruction::UDiv:
2260   case Instruction::SDiv:
2261   case Instruction::SRem:
2262   case Instruction::URem:
2263   case Instruction::Add:
2264   case Instruction::FAdd:
2265   case Instruction::Sub:
2266   case Instruction::FSub:
2267   case Instruction::FNeg:
2268   case Instruction::Mul:
2269   case Instruction::FMul:
2270   case Instruction::FDiv:
2271   case Instruction::FRem:
2272   case Instruction::Shl:
2273   case Instruction::LShr:
2274   case Instruction::AShr:
2275   case Instruction::And:
2276   case Instruction::Or:
2277   case Instruction::Xor: {
2278     // Just widen unops and binops.
2279     SmallVector<Value *, 2> Ops;
2280     for (VPValue *VPOp : operands())
2281       Ops.push_back(State.get(VPOp));
2282 
2283     Value *V = Builder.CreateNAryOp(Opcode, Ops);
2284 
2285     if (auto *VecOp = dyn_cast<Instruction>(V)) {
2286       applyFlags(*VecOp);
2287       applyMetadata(*VecOp);
2288     }
2289 
2290     // Use this vector value for all users of the original instruction.
2291     State.set(this, V);
2292     break;
2293   }
2294   case Instruction::ExtractValue: {
2295     assert(getNumOperands() == 2 && "expected single level extractvalue");
2296     Value *Op = State.get(getOperand(0));
2297     Value *Extract = Builder.CreateExtractValue(
2298         Op, cast<VPConstantInt>(getOperand(1))->getZExtValue());
2299     State.set(this, Extract);
2300     break;
2301   }
2302   case Instruction::Freeze: {
2303     Value *Op = State.get(getOperand(0));
2304     Value *Freeze = Builder.CreateFreeze(Op);
2305     State.set(this, Freeze);
2306     break;
2307   }
2308   case Instruction::ICmp:
2309   case Instruction::FCmp: {
2310     // Widen compares. Generate vector compares.
2311     bool FCmp = Opcode == Instruction::FCmp;
2312     Value *A = State.get(getOperand(0));
2313     Value *B = State.get(getOperand(1));
2314     Value *C = nullptr;
2315     if (FCmp) {
2316       C = Builder.CreateFCmp(getPredicate(), A, B);
2317     } else {
2318       C = Builder.CreateICmp(getPredicate(), A, B);
2319     }
2320     if (auto *I = dyn_cast<Instruction>(C)) {
2321       applyFlags(*I);
2322       applyMetadata(*I);
2323     }
2324     State.set(this, C);
2325     break;
2326   }
2327   case Instruction::Select: {
2328     VPValue *CondOp = getOperand(0);
2329     Value *Cond = State.get(CondOp, vputils::isSingleScalar(CondOp));
2330     Value *Op0 = State.get(getOperand(1));
2331     Value *Op1 = State.get(getOperand(2));
2332     Value *Sel = State.Builder.CreateSelect(Cond, Op0, Op1);
2333     State.set(this, Sel);
2334     if (auto *I = dyn_cast<Instruction>(Sel)) {
2335       if (isa<FPMathOperator>(I))
2336         applyFlags(*I);
2337       applyMetadata(*I);
2338     }
2339     break;
2340   }
2341   default:
2342     // This instruction is not vectorized by simple widening.
2343     LLVM_DEBUG(dbgs() << "LV: Found an unhandled opcode : "
2344                       << Instruction::getOpcodeName(Opcode));
2345     llvm_unreachable("Unhandled instruction!");
2346   } // end of switch.
2347 
2348 #if !defined(NDEBUG)
2349   // Verify that VPlan type inference results agree with the type of the
2350   // generated values.
2351   assert(VectorType::get(State.TypeAnalysis.inferScalarType(this), State.VF) ==
2352              State.get(this)->getType() &&
2353          "inferred type and type from generated instructions do not match");
2354 #endif
2355 }
2356 
2357 InstructionCost VPWidenRecipe::computeCost(ElementCount VF,
2358                                            VPCostContext &Ctx) const {
2359   switch (Opcode) {
2360   case Instruction::UDiv:
2361   case Instruction::SDiv:
2362   case Instruction::SRem:
2363   case Instruction::URem:
2364     // If the div/rem operation isn't safe to speculate and requires
2365     // predication, then the only way we can even create a vplan is to insert
2366     // a select on the second input operand to ensure we use the value of 1
2367     // for the inactive lanes. The select will be costed separately.
2368   case Instruction::FNeg:
2369   case Instruction::Add:
2370   case Instruction::FAdd:
2371   case Instruction::Sub:
2372   case Instruction::FSub:
2373   case Instruction::Mul:
2374   case Instruction::FMul:
2375   case Instruction::FDiv:
2376   case Instruction::FRem:
2377   case Instruction::Shl:
2378   case Instruction::LShr:
2379   case Instruction::AShr:
2380   case Instruction::And:
2381   case Instruction::Or:
2382   case Instruction::Xor:
2383   case Instruction::Freeze:
2384   case Instruction::ExtractValue:
2385   case Instruction::ICmp:
2386   case Instruction::FCmp:
2387   case Instruction::Select:
2388     return getCostForRecipeWithOpcode(getOpcode(), VF, Ctx);
2389   default:
2390     llvm_unreachable("Unsupported opcode for instruction");
2391   }
2392 }
