2405 void VPWidenCastRecipe::execute(VPTransformState &State) {
2406   auto &Builder = State.Builder;
2407   /// Vectorize casts.
2408   assert(State.VF.isVector() && "Not vectorizing?");
2409   Type *DestTy = VectorType::get(getResultType(), State.VF);
2410   VPValue *Op = getOperand(0);
2411   Value *A = State.get(Op);
2412   Value *Cast = Builder.CreateCast(Instruction::CastOps(Opcode), A, DestTy);
2413   State.set(this, Cast);
2414   if (auto *CastOp = dyn_cast<Instruction>(Cast)) {
2415     applyFlags(*CastOp);
2416     applyMetadata(*CastOp);
2417   }
2418 }
