2461 bool VPWidenIntOrFpInductionRecipe::isCanonical() const {
2462   // The step may be defined by a recipe in the preheader (e.g. if it requires
2463   // SCEV expansion), but for the canonical induction the step is required to be
2464   // 1, which is represented as live-in.
2465   auto *StepC = dyn_cast<VPConstantInt>(getStepValue());
2466   auto *StartC = dyn_cast<VPConstantInt>(getStartValue());
2467   return StartC && StartC->isZero() && StepC && StepC->isOne() &&
2468          getScalarType() == getRegion()->getCanonicalIVType();
2469 }
