2471 void VPDerivedIVRecipe::execute(VPTransformState &State) {
2472   assert(!State.Lane && "VPDerivedIVRecipe being replicated.");
2473 
2474   // Fast-math-flags propagate from the original induction instruction.
2475   IRBuilder<>::FastMathFlagGuard FMFG(State.Builder);
2476   if (FPBinOp)
2477     State.Builder.setFastMathFlags(FPBinOp->getFastMathFlags());
2478 
2479   Value *Step = State.get(getStepValue(), VPLane(0));
2480   Value *Index = State.get(getOperand(1), VPLane(0));
2481   Value *DerivedIV = emitTransformedIndex(
2482       State.Builder, Index, getStartValue()->getLiveInIRValue(), Step, Kind,
2483       cast_if_present<BinaryOperator>(FPBinOp));
2484   DerivedIV->setName(Name);
2485   State.set(this, DerivedIV, VPLane(0));
2486 }
